function c(t){if(t==null||t===""||t==="--")return null;const n=parseFloat(t);return isNaN(n)?null:n}function g(){const t=new Date,n=t.getMonth()+1,e=t.getDate();return t.getFullYear()+"-"+(n<10?"0":"")+n+"-"+(e<10?"0":"")+e}function h(t){const n=g();return t.map((e,r)=>{const E=e.split("").reduce((s,a)=>s+a.charCodeAt(0),0),l=s=>{const a=Math.sin(E+s)*1e4;return a-Math.floor(a)},u=(l(1)-.48)*6,F=1+(l(2)-.5)*.5,T=F/(1+u/100),o=["沪深300指数A","中证500指数C","创业板指基","上证50增强","军工ETF联接","医药卫生ETF","新能源车ETF","半导体ETF","食品饮料ETF","银行ETF联接","券商ETF基金","地产ETF链接"],d=o[r%o.length]+(r>=o.length?` ${Math.floor(r/o.length)+1}号`:"");return{FCODE:e,SHORTNAME:d,GSZ:c(F.toFixed(4)),GSZZL:c(u.toFixed(2)),DWJZ:c(T.toFixed(4)),GZTIME:n+" 15:00",PDATE:n,IS_MOCK:!0}})}export{h as generateMockData};
